#[op_interface_impl]
impl MirToLlvmConversion for ClusterBarrierOp {
    fn convert(
        &self,
        ctx: &mut Context,
        rewriter: &mut DialectConversionRewriter,
        _operands_info: &OperandsInfo,
    ) -> Result<()> {
        let recipe = match self.get_attr_nvvm_cluster_barrier_mode(ctx).as_deref() {
            Some(&ClusterBarrierModeAttr::Arrive) => (
                "llvm_nvvm_barrier_cluster_arrive",
                "barrier.cluster.arrive;",
            ),
            Some(&ClusterBarrierModeAttr::ArriveAligned) => (
                "llvm_nvvm_barrier_cluster_arrive_aligned",
                "barrier.cluster.arrive.aligned;",
            ),
            Some(&ClusterBarrierModeAttr::ArriveRelaxed) => (
                "llvm_nvvm_barrier_cluster_arrive_relaxed",
                "barrier.cluster.arrive.relaxed;",
            ),
            Some(&ClusterBarrierModeAttr::ArriveRelaxedAligned) => (
                "llvm_nvvm_barrier_cluster_arrive_relaxed_aligned",
                "barrier.cluster.arrive.relaxed.aligned;",
            ),
            Some(&ClusterBarrierModeAttr::Wait) => {
                ("llvm_nvvm_barrier_cluster_wait", "barrier.cluster.wait;")
            }
            Some(&ClusterBarrierModeAttr::WaitAligned) => (
                "llvm_nvvm_barrier_cluster_wait_aligned",
                "barrier.cluster.wait.aligned;",
            ),
            _ => {
                return pliron::input_err!(
                    self.get_operation().deref(ctx).loc(),
                    "nvvm.cluster_barrier mode has no generated lowering recipe",
                );
            }
        };
        let op = self.get_operation();
        let void_ty = llvm_types::VoidType::get(ctx);
        match context::lowering_options(ctx).intrinsic_backend {
            IntrinsicBackend::LlvmNvptx => {
                let function_ty = llvm_types::FuncType::get(ctx, void_ty.into(), vec![], false);
                call_intrinsic(ctx, rewriter, op, recipe.0, function_ty, vec![])?;
            }
            IntrinsicBackend::LibNvvm => {
                inline_asm_convergent(ctx, rewriter, void_ty.into(), vec![], recipe.1, "~{memory}");
            }
        }
        rewriter.erase_operation(ctx, op);
        Ok(())
    }
}

#[op_interface_impl]
impl MirToLlvmConversion for ClusterSyncOp {
    fn convert(
        &self,
        ctx: &mut Context,
        rewriter: &mut DialectConversionRewriter,
        _operands_info: &OperandsInfo,
    ) -> Result<()> {
        let op = self.get_operation();
        let void_ty = llvm_types::VoidType::get(ctx);
        match context::lowering_options(ctx).intrinsic_backend {
            IntrinsicBackend::LlvmNvptx => {
                let function_ty = llvm_types::FuncType::get(ctx, void_ty.into(), vec![], false);
                call_intrinsic(
                    ctx,
                    rewriter,
                    op,
                    "llvm_nvvm_barrier_cluster_arrive_aligned",
                    function_ty,
                    vec![],
                )?;
                call_intrinsic(
                    ctx,
                    rewriter,
                    op,
                    "llvm_nvvm_barrier_cluster_wait_aligned",
                    function_ty,
                    vec![],
                )?;
            }
            IntrinsicBackend::LibNvvm => {
                inline_asm_convergent(
                    ctx,
                    rewriter,
                    void_ty.into(),
                    vec![],
                    "barrier.cluster.arrive.aligned; barrier.cluster.wait.aligned;",
                    "~{memory}",
                );
            }
        }
        rewriter.erase_operation(ctx, op);
        Ok(())
    }
}

fn convert_generated_wgmma_control(
    ctx: &mut Context,
    rewriter: &mut DialectConversionRewriter,
    op: Ptr<Operation>,
    intrinsic_name: &str,
    ptx: &str,
    has_immediate: bool,
) -> Result<()> {
    let operands: Vec<_> = op.deref(ctx).operands().collect();
    if operands.len() != usize::from(has_immediate) {
        return pliron::input_err!(
            op.deref(ctx).loc(),
            "generated WGMMA control has the wrong operand count",
        );
    }
    let void_ty = llvm_types::VoidType::get(ctx);
    match context::lowering_options(ctx).intrinsic_backend {
        IntrinsicBackend::LlvmNvptx => {
            let arguments = if has_immediate {
                vec![IntegerType::get(ctx, 64, Signedness::Signless).into()]
            } else {
                vec![]
            };
            let function_ty = llvm_types::FuncType::get(ctx, void_ty.into(), arguments, false);
            call_intrinsic(ctx, rewriter, op, intrinsic_name, function_ty, operands)?;
        }
        IntrinsicBackend::LibNvvm => {
            let constraints = if has_immediate {
                "n,~{memory}"
            } else {
                "~{memory}"
            };
            inline_asm_convergent(ctx, rewriter, void_ty.into(), operands, ptx, constraints);
        }
    }
    rewriter.erase_operation(ctx, op);
    Ok(())
}

