#[op_interface_impl]
impl MirToLlvmConversion for Barrier0Op {
    fn convert(
        &self,
        ctx: &mut Context,
        rewriter: &mut DialectConversionRewriter,
        _operands_info: &OperandsInfo,
    ) -> Result<()> {
        let op = self.get_operation();
        let void_ty = llvm_types::VoidType::get(ctx);
        match context::lowering_options(ctx).intrinsic_backend {
            IntrinsicBackend::LlvmNvptx => {
                let i32_ty = IntegerType::get(ctx, 32, Signedness::Signless);
                let barrier_id = create_i32_const(ctx, rewriter, 0);
                let function_ty =
                    llvm_types::FuncType::get(ctx, void_ty.into(), vec![i32_ty.into()], false);
                call_intrinsic(
                    ctx,
                    rewriter,
                    op,
                    "llvm_nvvm_barrier_cta_sync_aligned_all",
                    function_ty,
                    vec![barrier_id],
                )?;
            }
            IntrinsicBackend::LibNvvm => {
                inline_asm_convergent(
                    ctx,
                    rewriter,
                    void_ty.into(),
                    vec![],
                    "bar.sync 0;",
                    "~{memory}",
                );
            }
        }
        rewriter.erase_operation(ctx, op);
        Ok(())
    }
}

